{
  "name": "@dostarora97/html2md",
  "version": "0.1.2",
  "license": "MIT",
  "exports": "./mod.ts",
  "publish": {
    "exclude": [
      "docs/api/",
      ".github/",
      "coverage/",
      ".claude/",
      ".entire/",
      ".vscode/",
      ".idea/",
      "lefthook.yml",
      ".mise.toml",
      ".gitattributes",
      ".gitignore",
      ".editorconfig",
      "CLAUDE.md",
      "mod_test.ts",
      "cli_test.ts"
    ]
  },
  "tasks": {
    "dev": {
      "command": "deno test --watch",
      "description": "Watch mode — re-run tests on file change"
    },
    "install": "deno install --global --allow-read --allow-env --config ./deno.json --no-lock --name html2md -f ./cli.ts",
    "fmt": "deno fmt",
    "fmt:check": "deno fmt --check",
    "lint": "deno lint",
    "test": {
      "command": "deno test --parallel --allow-run",
      "description": "Run unit tests"
    },
    "test:coverage": {
      "command": "deno test --parallel --allow-run --coverage=coverage/raw",
      "description": "Run tests with coverage collection"
    },
    "test:doc": {
      "command": "deno test --doc mod.ts",
      "description": "Test JSDoc code examples in mod.ts"
    },
    "coverage": {
      "command": "deno coverage coverage/raw --lcov --output=coverage/lcov.info",
      "dependencies": ["test:coverage"],
      "description": "Run tests then generate lcov coverage report"
    },
    "coverage:html": {
      "command": "deno coverage coverage/raw --html --output=coverage/html",
      "dependencies": ["test:coverage"],
      "description": "Run tests then generate HTML coverage report"
    },
    "check": "deno check mod.ts cli.ts",
    "doc:lint": "deno doc --lint mod.ts",
    "doc:gen": "deno doc --html --name='html2md' --output=docs/api mod.ts",
    "ci": {
      "command": "deno task fmt:check && deno task lint && deno task doc:lint && deno task check && deno task test",
      "description": "Full CI pipeline: fmt + lint + doc:lint + typecheck + test"
    },
    "outdated": "deno outdated",
    "update": "deno outdated --update",
    "update:latest": "deno outdated --update --latest",
    "publish-dry": "deno publish --dry-run --allow-dirty",
    "publish": "deno publish"
  },
  "compilerOptions": {
    "lib": ["deno.window", "dom"],
    "strict": true,
    "verbatimModuleSyntax": true
  },
  "lint": {
    "rules": {
      "tags": ["recommended"],
      "include": [
        "ban-untagged-todo",
        "no-slow-types",
        "verbatim-module-syntax"
      ]
    },
    "exclude": ["docs/api/", "coverage/"]
  },
  "fmt": {
    "lineWidth": 80,
    "indentWidth": 2,
    "semiColons": true,
    "singleQuote": false,
    "proseWrap": "always",
    "exclude": ["docs/api/", "coverage/", ".idea/"]
  },
  "test": {
    "exclude": ["docs/api/", "coverage/"]
  },
  "lock": {
    "frozen": true
  },
  "imports": {
    "@std/cli": "jsr:@std/cli@^1.0.28",
    "turndown": "npm:turndown@^7.2.2",
    "@mozilla/readability": "npm:@mozilla/readability@^0.6.0",
    "linkedom": "npm:linkedom@^0.18.12",
    "@std/assert": "jsr:@std/assert@1"
  },
  "exclude": ["node_modules", "docs/api/", "coverage/", ".idea/"]
}

